// ── Cache check (Supabase) ──
// TODO: Before calling expensive APIs, check:
// SELECT * FROM agent_cache WHERE cache_key = MD5(city+area+business_type+agent_id)
//   AND updated_at > NOW() - INTERVAL '7 days'
// If cache hit → return cached data immediately
// Implementation: add a Supabase HTTP call before API calls with cache_key lookup

const all = $input.all();
const inputs = $('Parse & Validate Inputs').item.json;

// ── PARSE SERP RESULTS ──
let costArticles = [];
let salaryArticles = [];
for (const item of all) {
  const j = item.json;
  if (j?.organic_results && Array.isArray(j.organic_results)) {
    if (costArticles.length === 0) costArticles = j.organic_results;
    else salaryArticles = j.organic_results;
  }
}

const costText = costArticles.slice(0, 6).map((r, i) =>
  `${i+1}. ${r.title||''}\n   ${(r.snippet||'').slice(0,200)}\n   Source: ${r.displayed_link||''}`
).join('\n\n');

const salaryText = salaryArticles.slice(0, 6).map((r, i) =>
  `${i+1}. ${r.title||''}\n   ${(r.snippet||'').slice(0,200)}\n   Source: ${r.displayed_link||''}`
).join('\n\n');

// ── PARSE A1 DATA ──
let a1 = {};
try { a1 = JSON.parse(inputs.a1_competitor_data || '{}')?.outputs || {}; } catch(e) {}

// ── PARSE A2 DATA ──
let a2 = {};
try { a2 = JSON.parse(inputs.a2_rent_data || '{}')?.outputs || {}; } catch(e) {}

// ── PARSE A3 DATA ──
let a3 = {};
try { a3 = JSON.parse(inputs.a3_market_data || '{}')?.outputs || {}; } catch(e) {}

// ── BUILD CONTEXT STRINGS ──
const a1Context = Object.keys(a1).length > 0
  ? `Competitor Density: ${a1.competitor_density_score||'N/A'}/100\nSaturation: ${a1.saturation_level||'N/A'}\nOpportunity Gaps: ${(a1.opportunity_gaps||[]).join('; ')}`
  : 'Not provided';

const a2Context = Object.keys(a2).length > 0
  ? `Actual Rent Range: ${a2.rent_range_actual?.min||'N/A'} – ${a2.rent_range_actual?.max||'N/A'}\nMedian Rent: ${a2.rent_range_actual?.median||'N/A'}\nDeposit Estimate: ${a2.deposit_estimate||'N/A'}\nTransport Score: ${a2.transport_access_score||'N/A'}/10\nLocation Verdict: ${a2.overall_location_verdict||'N/A'}`
  : 'Not provided';

const a3Context = Object.keys(a3).length > 0
  ? `Demand Trend: ${a3.demand_trend||'N/A'}\nMarket Maturity: ${a3.market_maturity_stage||'N/A'}\nCompetitor Threat: ${a3.competitor_threat_level||'N/A'}\nRegulatory Flags: ${(a3.regulatory_flags||[]).map(r => r.license_name + ' (' + r.estimated_cost + ')').join('; ')||'None listed'}`
  : 'Not provided';

// ── MARKETING BUDGET SIGNAL FROM A1 ──
// High saturation = needs higher marketing spend to cut through
const marketingMultiplier = a1.saturation_level === 'High' ? 'HIGH — saturated market requires aggressive marketing'
  : a1.saturation_level === 'Medium' ? 'MEDIUM — moderate marketing needed'
  : 'LOW — low competition means organic growth likely';

// ── CONTINGENCY SIGNAL FROM A3 ──
const contingencySignal = a3.demand_trend === 'Falling' ? 'HIGH — falling demand requires larger buffer'
  : a3.competitor_threat_level === 'High' ? 'MEDIUM-HIGH — strong competition increases risk'
  : 'STANDARD — normal contingency applies';

return [{ json: {
  // Pass-through
  business_type:           inputs.business_type,
  industry_category:       inputs.industry_category,
  city:                    inputs.city,
  area:                    inputs.area,
  country:                 inputs.country,
  currency:                inputs.currency,
  space_size_range:        inputs.space_size_range,
  preferred_sqft:          inputs.preferred_sqft,
  monthly_rent_budget_max: inputs.monthly_rent_budget_max,
  staff_count_range:       inputs.staff_count_range,
  setup_budget:            inputs.setup_budget,
  business_model:          inputs.business_model,
  lease_term_years:        inputs.lease_term_years,
  equipment_owned:         inputs.equipment_owned,
  email:                   inputs.email,
  // Context for AI
  cost_articles_text:      costText || 'No cost data found.',
  salary_articles_text:    salaryText || 'No salary data found.',
  a1_context:              a1Context,
  a2_context:              a2Context,
  a3_context:              a3Context,
  marketing_multiplier:    marketingMultiplier,
  contingency_signal:      contingencySignal,
  // Raw for HTML
  a2_rent_median:          a2.rent_range_actual?.median || null,
  a2_deposit:              a2.deposit_estimate || null,
  a3_regulatory_flags:     a3.regulatory_flags || [],
  data_sources: {
    cost_articles:   costArticles.length,
    salary_articles: salaryArticles.length,
    a1_integrated:   Object.keys(a1).length > 0,
    a2_integrated:   Object.keys(a2).length > 0,
    a3_integrated:   Object.keys(a3).length > 0
  }
}}];

const rawText = $input.first().json.output || '';
let analysis;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = { parse_error: true, raw_response: rawText };
}

const d = $('Process & Merge All Data').item.json;

return [{
  json: {
    agent_id:   'A4',
    agent_name: 'Cost Projection',
    status:     analysis.parse_error ? 'error' : 'success',
    timestamp:  new Date().toISOString(),
    email:      d.email,
    inputs_used: {
      location:                `${d.area}, ${d.city}, ${d.country}`,
      industry:                d.industry_category,
      business_model:          d.business_model,
      space_size_range:        d.space_size_range,
      staff_count_range:       d.staff_count_range,
      setup_budget:            `${d.currency}${d.setup_budget}`,
      monthly_rent_budget_max: `${d.currency}${d.monthly_rent_budget_max}`,
      currency:                d.currency
    },
    data_sources: d.data_sources,
    a3_regulatory_flags: d.a3_regulatory_flags,
    outputs: {
      setup_cost_breakdown:    analysis.setup_cost_breakdown,
      setup_cost_estimate:     analysis.setup_cost_estimate,
      monthly_operating_cost:  analysis.monthly_operating_cost,
      financial_projections:   analysis.financial_projections,
      cost_risk_flags:         analysis.cost_risk_flags,
      cost_optimisation_tips:  analysis.cost_optimisation_tips,
      overall_financial_verdict: analysis.overall_financial_verdict,
      agent_notes:             analysis.agent_notes
    }
  }
}];


// ── Output validation ──
const required_keys = Object.keys(analysis).filter(k => !k.startsWith('_') && !k.startsWith('raw'));
if (required_keys.length < 3 || analysis.parse_error) {
  analysis._validation_failed = true;
  analysis._validation_reason = analysis.parse_error ? 'JSON parse error' : 'Insufficient output fields (' + required_keys.length + ')';
}
analysis._validated_at = new Date().toISOString();
analysis._agent_version = 'v2';
